#include <stdio.h>

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        long cum1 = 0, cum2 = 0;
        int maxLead = 0, winner = 0;
        for (int i = 0; i < N; ++i) {
            int s, t; scanf("%d %d", &s, &t);
            cum1 += s; cum2 += t;
            long diff = cum1 - cum2;
            int lead = diff > 0 ? diff : -diff;
            if (lead > maxLead) {
                maxLead = lead;
                winner = diff > 0 ? 1 : 2;
            }
        }
        printf("%d %d\n", winner, maxLead);
    }
    return 0;
}

