import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            int N = fs.nextInt();
            long cum1 = 0, cum2 = 0;
            int maxLead = 0, winner = 0;
            for (int i = 0; i < N; i++) {
                int s = fs.nextInt();
                int t = fs.nextInt();
                cum1 += s;
                cum2 += t;
                long diff = cum1 - cum2;
                int lead = diff > 0 ? (int)diff : (int)-diff;
                if (lead > maxLead) {
                    maxLead = lead;
                    winner = diff > 0 ? 1 : 2;
                }
            }
            sb.append(winner).append(' ').append(maxLead).append('\n');
        }
        System.out.print(sb.toString());
    }

    // Simple fast scanner
    static class FastScanner {
        private final BufferedInputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream stream) { in = new BufferedInputStream(stream); }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        int nextInt() throws IOException {
            int c, sign = 1, val = 0;
            do { c = readByte(); } while (c <= ' ');
            if (c == '-') { sign = -1; c = readByte(); }
            while (c > ' ') {
                val = val * 10 + (c - '0');
                c = readByte();
            }
            return val * sign;
        }
    }
}

